import{_ as t,o as e,c as n,a2 as s}from"./chunks/framework.BFZItJIV.js";const g=JSON.parse('{"title":"什么是 Clawline","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is.md","filePath":"guide/what-is.md","lastUpdated":1774182726000}'),l={name:"guide/what-is.md"};function r(o,a,d,i,p,h){return e(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="什么是-clawline" tabindex="-1">什么是 Clawline <a class="header-anchor" href="#什么是-clawline" aria-label="Permalink to &quot;什么是 Clawline&quot;">​</a></h1><h2 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h2><p>你在用 <a href="https://github.com/openclaw/openclaw" target="_blank" rel="noreferrer">OpenClaw</a> 构建 AI Agent。Agent 运行得很好，但用户怎么用它？</p><p><strong>现有方案的困境：</strong></p><table tabindex="0"><thead><tr><th>方案</th><th>问题</th></tr></thead><tbody><tr><td>依赖 Telegram / Discord</td><td>用户必须安装特定 App；国内访问不友好；UI 不可控；数据在别人手里</td></tr><tr><td>依赖微信公众号</td><td>审核周期长；接口限制多；被封号直接断联</td></tr><tr><td>自己从零搭建</td><td>WebSocket 连接管理、鉴权、消息路由、文件上传、断线重连、流式渲染……工程量巨大</td></tr><tr><td>暴露 Webhook 端口</td><td>Agent 需要公网 IP，内网部署直接不可用</td></tr></tbody></table><p>核心矛盾：<strong>Agent 很强大，但用户触达很困难。</strong></p><h2 id="方案" tabindex="-1">方案 <a class="header-anchor" href="#方案" aria-label="Permalink to &quot;方案&quot;">​</a></h2><p>Clawline 是 OpenClaw 的 <strong>Web 接入方案</strong>。核心只需要一个插件，按需叠加组件：</p><h3 id="两种部署模式" tabindex="-1">两种部署模式 <a class="header-anchor" href="#两种部署模式" aria-label="Permalink to &quot;两种部署模式&quot;">​</a></h3><h4 id="🚀-简单模式-直连" tabindex="-1">🚀 简单模式：直连 <a class="header-anchor" href="#🚀-简单模式-直连" aria-label="Permalink to &quot;🚀 简单模式：直连&quot;">​</a></h4><p><strong>只装一个插件，零额外服务。</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户浏览器                    内网 Agent</span></span>
<span class="line"><span>┌──────────┐   ws://直连   ┌──────────────┐</span></span>
<span class="line"><span>│Client Web │ ───────────→ │Channel Plugin│</span></span>
<span class="line"><span>│           │ ←─────────── │ (OpenClaw)   │</span></span>
<span class="line"><span>└──────────┘               └──────────────┘</span></span></code></pre></div><p>Channel Plugin 以 <code>connectionMode: &quot;websocket&quot;</code> 启动，直接在本地开 WebSocket 端口。<strong>内网、局域网、本机开发——开箱即用。</strong> 不需要任何额外服务。</p><p>适用：内网部署、个人使用、开发调试、局域网团队。</p><h4 id="🌐-relay-模式-跨网络" tabindex="-1">🌐 Relay 模式：跨网络 <a class="header-anchor" href="#🌐-relay-模式-跨网络" aria-label="Permalink to &quot;🌐 Relay 模式：跨网络&quot;">​</a></h4><p><strong>加一个 Relay Gateway，穿透任何网络。</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户浏览器                  公网服务器                内网 Agent</span></span>
<span class="line"><span>┌──────────┐    wss://    ┌──────────────┐   wss://  ┌──────────────┐</span></span>
<span class="line"><span>│Client Web │ ──────────→ │Relay Gateway │ ←──────── │Channel Plugin│</span></span>
<span class="line"><span>│(React PWA)│ ←────────── │ (中转+鉴权)  │ ────────→ │ (OpenClaw)   │</span></span>
<span class="line"><span>└──────────┘              └──────────────┘           └──────────────┘</span></span></code></pre></div><p>Channel Plugin 以 <code>connectionMode: &quot;relay&quot;</code> <strong>主动连出</strong>到 Relay——无需开端口、无需公网 IP。Relay 负责中转、鉴权、文件上传。</p><p>适用：公网暴露、多用户共享、多节点管理、企业部署。</p><h3 id="三个组件" tabindex="-1">三个组件 <a class="header-anchor" href="#三个组件" aria-label="Permalink to &quot;三个组件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>组件</th><th>说明</th><th>必须？</th></tr></thead><tbody><tr><td>📡 <strong>Channel Plugin</strong></td><td>OpenClaw 插件，让 Agent 能通过 WebSocket 收发消息</td><td>✅ 核心</td></tr><tr><td>💬 <strong>Client Web</strong></td><td>开箱即用的聊天前端（React + Vite，PWA 支持）</td><td>可选（你也可以自己写前端）</td></tr><tr><td>🌐 <strong>Relay Gateway</strong></td><td>WebSocket 中转网关 + 鉴权 + 文件上传 + 管理后台</td><td>可选（仅跨网络时需要）</td></tr></tbody></table><p><strong>关键设计：</strong> Relay 模式下，Channel Plugin 主动连接 Relay（箭头方向是 <code>←</code>），而不是 Relay 回调 Agent。Agent 可以在任何网络环境运行——内网、VPN、防火墙后面——只要能访问 Relay 的地址。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./architecture.html">架构概览</a> — 深入了解三端协作机制</li><li><a href="./quickstart.html">快速开始</a> — 5 分钟跑起来</li></ul>`,24)])])}const u=t(l,[["render",r]]);export{g as __pageData,u as default};
